function safe(v) {
  if (v === null || v === undefined) return "";
  return String(v);
}

const total = items.length;

return items.map((item, index) => {
  const j = item.json;
  const payload = j.payload || {};

  let nota = 100;

  if (total > 1) {
    nota = 100 - (25 * index) / (total - 1);
  }

  // Arredondamento + clamp
  nota = Math.round(nota);
  nota = Math.max(75, Math.min(100, nota));

  return {
    json: {
      id: j.id || null,
      score_final: j.score_final || 0,
      nota: parseInt(nota),

      cnpj: safe(payload.cnpj),
      n_exibicoes: j.n_exibicoes || 0,
      plano_categoria: j.plano_categoria || null,

      full_profile: {
        identidade: {
          nome_empresa: safe(payload.nome_empresa),
          modelo_negocio: safe(payload.modelo_negocio)
        },
        contato: {
          url_site: safe(payload.site),
          telefones: safe(payload.telefone),
          emails: safe(payload.email)
        }
      }
    }
  };
});

